import React, { useContext } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Row, Col, ListGroup, Image, Form, Button, Card, Container } from 'react-bootstrap';
// Contextos necesarios
import { CartContext } from '../context/CartContext';
import { SettingsContext } from '../context/SettingsContext';
// Componentes de feedback
import Message from '../components/Message'; 

const CartScreen = () => {
    const navigate = useNavigate();
    const { cartItems, removeFromCart, updateCartItemQty } = useContext(CartContext);
    const { settings } = useContext(SettingsContext);
    const currencySymbol = settings.currencySymbol || '$';

    // Sumar el total de artículos y el precio total
    const totalItems = cartItems.reduce((acc, item) => acc + item.qty, 0);
    const totalPrice = cartItems.reduce((acc, item) => acc + item.qty * item.price, 0);

    const checkoutHandler = () => {
        // Redirige al login. Si ya está logueado, ProtectedRoute lo enviará a /shipping.
        navigate('/login?redirect=/shipping');
    };
    
    // Función para cambiar la cantidad en el carrito
    const qtyChangeHandler = (id, e) => {
        const newQty = Number(e.target.value);
        updateCartItemQty(id, newQty);
    };

    return (
        <Container className="py-5" style={{ minHeight: '80vh', backgroundColor: 'var(--secondary-bg-color)' }}>
            <h1 className="text-4xl font-bold mb-4 border-b pb-2 text-slate-800">Carrito de Compras</h1>
            
            <Row>
                <Col md={8}>
                    {cartItems.length === 0 ? (
                        // Mensaje si el carrito está vacío
                        <Message variant='info'>
                            Tu carrito está vacío. <Link to='/' style={{ color: 'var(--cta-color)' }}>Volver a la tienda</Link>
                        </Message>
                    ) : (
                        // Lista de Artículos
                        <ListGroup variant='flush' className="rounded-xl shadow-lg border-0">
                            {cartItems.map((item) => (
                                <ListGroup.Item 
                                    key={item.product} 
                                    className="d-flex align-items-center p-3 rounded-xl mb-3 border-0"
                                    style={{ backgroundColor: 'var(--card-bg-color)' }}
                                >
                                    {/* Imagen del Producto */}
                                    <Col md={2} className="p-0">
                                        <Image src={item.image} alt={item.name} fluid rounded className="border" style={{ objectFit: 'contain', maxHeight: '60px' }} />
                                    </Col>
                                    
                                    {/* Nombre/Link */}
                                    <Col md={4} className="p-0">
                                        <Link to={`/product/${item.sku || item.product}`} className="text-decoration-none text-slate-700 hover:text-slate-900 font-medium ms-3">
                                            {item.name}
                                        </Link>
                                    </Col>

                                    {/* Precio */}
                                    <Col md={2} className="p-0 text-center font-bold text-slate-800">
                                        {currencySymbol}{(item.price).toFixed(2)}
                                    </Col>

                                    {/* Selector de Cantidad */}
                                    <Col md={2} className="p-0">
                                        <Form.Control
                                            as='select'
                                            value={item.qty}
                                            onChange={(e) => qtyChangeHandler(item.product, e)}
                                            className="rounded-lg shadow-sm text-center"
                                            style={{ width: '75px', margin: '0 auto' }}
                                        >
                                            {/* Generar opciones hasta 10 (o hasta el stock real) */}
                                            {[...Array(10).keys()].map((x) => (
                                                <option key={x + 1} value={x + 1}>
                                                    {x + 1}
                                                </option>
                                            ))}
                                        </Form.Control>
                                    </Col>

                                    {/* Botón de Eliminar */}
                                    <Col md={2} className="p-0 text-end">
                                        <Button
                                            type='button'
                                            variant='light'
                                            onClick={() => removeFromCart(item.product)}
                                            className="rounded-full hover:bg-red-100 transition-colors"
                                        >
                                            <i className="fas fa-trash text-red-500"></i>
                                        </Button>
                                    </Col>
                                </ListGroup.Item>
                            ))}
                        </ListGroup>
                    )}
                </Col>

                {/* Resumen del Pedido (Sidebar) */}
                <Col md={4}>
                    <Card className="rounded-xl shadow-lg border-0 mt-4 mt-md-0" style={{ backgroundColor: 'var(--card-bg-color)' }}>
                        <ListGroup variant='flush'>
                            <ListGroup.Item className="bg-transparent p-4 border-b">
                                <h2 className="text-2xl font-bold mb-0 text-slate-800">
                                    Subtotal ({totalItems}) artículos
                                </h2>
                            </ListGroup.Item>

                            <ListGroup.Item className="bg-transparent p-4">
                                <Row>
                                    <Col className="font-medium text-lg">Total estimado:</Col>
                                    <Col className="text-end font-extrabold text-xl" style={{ color: 'var(--cta-color)' }}>
                                        {currencySymbol}{totalPrice.toFixed(2)}
                                    </Col>
                                </Row>
                            </ListGroup.Item>

                            <ListGroup.Item className="bg-transparent p-4 pt-0">
                                <Button
                                    type='button'
                                    className='btn-primary w-full rounded-full py-2 shadow-md'
                                    disabled={cartItems.length === 0}
                                    onClick={checkoutHandler}
                                >
                                    Proceder al Pago
                                </Button>
                            </ListGroup.Item>
                        </ListGroup>
                    </Card>
                </Col>
            </Row>
        </Container>
    );
};

export default CartScreen;
